+fn make_row(cols: u16, seed: u32) -> Vec<Cell> {
+    (0..cols)
+        .map(|col| {
+            let mut cell = Cell::new((b'a' + ((seed + u32::from(col)) % 26) as u8) as char);
+            cell.attrs = SgrAttrs {
+                fg: Color::Named(((seed + u32::from(col)) % 16) as u8),
+                bg: Color::Default,
+                ..SgrAttrs::default()
+            };
+            cell
+        })
+        .collect()
+}
