+        );
+
+        let id = format!("estimate_bytes_1k_{}cols", cols);
+        group.bench_function(BenchmarkId::from_parameter(id), |b| {
+            b.iter(|| {
+                let est = estimate_scrollback_heap_bytes(black_box(&scrollback));
+                black_box(est);
+            });
+        });
+    }
